var DEFAULT_SETTINGS = {
  apiKey: "",
  provider: "deepseek",
  model: "deepseek-chat",
  endpoint: "",
  language: "zh",
  scheduleTime: "06:00",
  outputFolder: "AI Builder OS",
  lastRunDate: ""
};

// src/main.ts
var BuilderOSPlugin = class extends import_obsidian4.Plugin {
  scheduleTimer = null;
  async onload() {
    await this.loadSettings();
    this.addSettingTab(new BuilderOSSettingTab(this.app, this));
    this.addRibbonIcon("bot", "AI Builder OS: \u751F\u6210\u65E5\u62A5", () => this.run());
    this.addCommand({
      id: "generate-digest",
      name: "\u751F\u6210\u4ECA\u65E5 AI Builder OS \u65E5\u62A5",
      callback: () => this.run()
    });
    this.addCommand({
      id: "open-settings",
      name: "\u6253\u5F00 AI Builder OS \u8BBE\u7F6E",
      callback: () => {
        this.app.setting.open();
        this.app.setting.openTabById("aba");
      }
    });
    this.scheduleNextRun();
  }
  onunload() {
    if (this.scheduleTimer !== null) {
      window.clearInterval(this.scheduleTimer);
    }
  }
  // -- Settings persistence --------------------------------------------------
  async loadSettings() {
    this.settings = Object.assign({}, DEFAULT_SETTINGS, await this.loadData());
  }
  async saveSettings() {
    await this.saveData(this.settings);
  }
  // -- Main run --------------------------------------------------------------
  async run() {
    const notice = new import_obsidian4.Notice("AI Builder OS: \u6B63\u5728\u83B7\u53D6\u6570\u636E...", 0);
    try {
      if (!this.settings.apiKey) {
        notice.hide();
        new import_obsidian4.Notice("\u274C AI Builder OS: \u8BF7\u5148\u5728\u8BBE\u7F6E\u4E2D\u586B\u5199 API Key", 5e3);
        return;
      }
      const result = await runGeneration(this.settings);
      for (const file of result.files) {
        await this.ensureFolder(file.path);
        const exists = this.app.vault.getAbstractFileByPath(file.path);
        if (exists) {
          await this.app.vault.modify(exists, file.content);
        } else {
          await this.app.vault.create(file.path, file.content);
        }
      }
      this.settings.lastRunDate = result.date;
      await this.saveSettings();
      notice.hide();
      new import_obsidian4.Notice(
        `\u2705 AI Builder OS: ${result.date} \u65E5\u62A5\u5DF2\u751F\u6210 \u2014 ${result.opinionCount} \u4E2A\u89C2\u70B9 \xB7 ${result.files.length} \u4E2A\u6587\u4EF6`,
        8e3
      );
    } catch (err) {
      notice.hide();
      new import_obsidian4.Notice(`\u274C AI Builder OS: ${err.message}`, 8e3);
      console.error("[aba]", err);
    }
  }
  // -- Scheduling ------------------------------------------------------------
  scheduleNextRun() {
    this.scheduleTimer = window.setInterval(() => {
      if (this.shouldRunNow()) {
        this.run();
      }
    }, 5 * 60 * 1e3);
    this.registerInterval(this.scheduleTimer);
  }
  shouldRunNow() {
    const now = /* @__PURE__ */ new Date();
    const today2 = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}-${String(now.getDate()).padStart(2, "0")}`;
    if (this.settings.lastRunDate === today2) return false;
    const [h, m] = this.settings.scheduleTime.split(":").map(Number);
    if (isNaN(h) || isNaN(m)) return false;
    const currentMinutes = now.getHours() * 60 + now.getMinutes();
    const scheduleMinutes = h * 60 + m;
    return Math.abs(currentMinutes - scheduleMinutes) <= 5;
  }
  // -- Vault helpers ---------------------------------------------------------
  async ensureFolder(filePath) {
    const parts = filePath.split("/");
    parts.pop();
    let current = "";
    for (const part of parts) {
      current += (current ? "/" : "") + part;
      const exists = this.app.vault.getAbstractFileByPath(current);
      if (!exists) {
        await this.app.vault.createFolder(current);
      }
    }
  }
};
